import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';

const tabs = ['Faculty', 'Student'];
const hints = {
  Faculty: 'Staff ID / HOD ID / Admin ID',
  Student: 'Your Roll Number',
};

export default function Login() {
  const [activeTab, setActiveTab] = useState('Faculty');
  const [rollNumber, setRollNumber] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const roleRoutes = { admin: '/admin', hod: '/hod', faculty: '/faculty', student: '/student' };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!rollNumber.trim() || !password.trim()) {
      toast.error('Please enter roll number and password');
      return;
    }
    setLoading(true);
    try {
      const user = await login(rollNumber.trim(), password);
      toast.success(`Welcome, ${user.name}!`);
      navigate(roleRoutes[user.role] || '/');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed. Check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-header">
          <div className="login-logo">V</div>
          <h1>VEMU Institute of Technology</h1>
          <p>Student Mid Marks System</p>
        </div>

        <div className="login-tabs">
          {tabs.map(tab => (
            <button
              key={tab}
              className={`login-tab${activeTab === tab ? ' active' : ''}`}
              onClick={() => setActiveTab(tab)}
            >
              {tab}
            </button>
          ))}
        </div>

        <div className="login-body">
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">
                {activeTab === 'Student' ? 'Roll Number' : 'Employee / Roll Number'}
              </label>
              <input
                className="form-input"
                type="text"
                placeholder={`Enter ${hints[activeTab]}`}
                value={rollNumber}
                onChange={e => setRollNumber(e.target.value)}
                autoFocus
                autoComplete="username"
              />
            </div>

            <div className="form-group">
              <label className="form-label">Password</label>
              <input
                className="form-input"
                type="password"
                placeholder="Enter password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                autoComplete="current-password"
              />
            </div>

            <button className="btn-login" type="submit" disabled={loading}>
              {loading ? '⏳ Signing In...' : 'Sign In'}
            </button>
          </form>

          <div className="login-hint">
            Default password for new accounts:<br />
            <strong>Your Roll Number</strong>
          </div>
        </div>

        <div className="login-footer">© 2024 VEMU Institute of Technology</div>
      </div>
    </div>
  );
}
